spec.root_selector:
def hex2int:
  ascii_downcase | explode
  | reduce .[] as $c (0; . * 16 + (("0123456789abcdef"|explode) | index($c)));

((.result // "0x") | ltrimstr("0x") | .[0:64]) as $w
| [ { Finalized: ($w | hex2int) } ]

def hex2int: ascii_downcase | explode | reduce .[] as $c (0; . * 16 + (("0123456789abcdef"|explode) | index($c)));
def words: [range(0; length; 64) as $i | .[$i:$i+64]];
def addr_from_topic: "0x" + (.[26:66]);

(.result // [])
| (if length == 0 then []
   else
     map(
       . as $l
       | ($l.topics[0]) as $t0
       | ($l.topics[1] | ltrimstr("0x") | addr_from_topic) as $validator
       | ($l.data | ltrimstr("0x") | words) as $w
       | {
           blockNumber: ($l.blockNumber | ltrimstr("0x") | hex2int),
           txHash: $l.transactionHash,
           event: (if $t0 == "0x04173640a8102913cf3540e52f9d6d78ce7dcf5ca36252ec4b66a57325e76120"
                   then "SlashedFromIdleness"
                   else "SlashEnacted"
                   end),
           validator: $validator,
           txId: (if $t0 == "0x04173640a8102913cf3540e52f9d6d78ce7dcf5ca36252ec4b66a57325e76120"
                  then ("0x" + $w[0])
                  else null
                  end),
           epoch: (if $t0 == "0x04173640a8102913cf3540e52f9d6d78ce7dcf5ca36252ec4b66a57325e76120"
                  then ($w[1] | hex2int)
                  else ($w[0] | hex2int)
                  end),
           percentage: (if $t0 == "0x04173640a8102913cf3540e52f9d6d78ce7dcf5ca36252ec4b66a57325e76120"
                        then ($w[2] | hex2int)
                        else null
                        end)
         }
     )
     | sort_by(.blockNumber)
     | (if length > 15 then .[-15:] else . end)
     | reverse
   end)

def t0: .topics[0];

[
  {
    Total: ((.result // []) | length),
    FromIdleness: ((.result // []) | map(select(t0 == "0x04173640a8102913cf3540e52f9d6d78ce7dcf5ca36252ec4b66a57325e76120")) | length),
    Enacted: ((.result // []) | map(select(t0 == "0xce0fb8cdb70dc98c87f1cc721bf4c7457c107596f205b8e742fcd57e2a64865c")) | length)
  }
]

def hex2int:
  ascii_downcase | explode
  | reduce .[] as $c (0; . * 16 + (("0123456789abcdef"|explode) | index($c)));

def words:
  [range(0; length; 64) as $i | .[$i:$i+64]];

def as_array:
  if type == "array" then . else [.] end;

def byid($id):
  (as_array
   | map(select(type=="object" and ((.id|tostring) == ($id|tostring))))
   | .[0] // {});

def clamp_nonneg:
  if . > 0 then . else 0 end;

. as $resp
| ($resp | byid(1)) as $r1
| ($resp | byid(2)) as $r2
| ($resp | byid(3)) as $r3
| ($resp | byid(4)) as $r4
| ($resp | byid(5)) as $r5

| (($r1.result // "0x") | ltrimstr("0x") | .[0:64] | hex2int) as $epoch
| (($r4.result.timestamp // "0x0") | ltrimstr("0x") | hex2int) as $now
| (($r5.result // "0x") | ltrimstr("0x") | .[0:64] | hex2int) as $dur_s

| (($r2.result // "0x") | ltrimstr("0x") | words) as $odd
| (($r3.result // "0x") | ltrimstr("0x") | words) as $even
| (($odd[0] // "0") | hex2int) as $odd_start
| (($even[0] // "0") | hex2int) as $even_start
| (if ($epoch % 2) == 1 then $odd_start else $even_start end) as $start

| ($start + $dur_s) as $next
| (($next - $now) | clamp_nonneg) as $remain_s

| [ {
    "Epoch duration (min)": (($dur_s / 60) | floor),
    "Next epoch in (min)": (($remain_s / 60) | floor)
  } ]

